import sqlite3
from typing import Dict

def get_order(user_id: int, order_id: int) -> Dict:
    conn = sqlite3.connect('database.db')
    cursor = conn.cursor()

    query = """
        SELECT *
        FROM orders
        WHERE user_id = ? AND id = ?
    """

    try:
        cursor.execute(query, (user_id, order_id))
        row = cursor.fetchone()
        
        if row is None:
            return {}
        
        order_data = {
            'id': row[0],
            'user_id': row[1],
            # Add other fields as needed
        }
        
        return order_data
    
    except sqlite3.Error as e:
        print(f"An error occurred: {e}")
    
    finally:
        conn.close()

